{"code":"from decimal import Decimal, ROUND_HALF_UP

def migrate(input_record: str) -> str:
    # Preserve fixed-width input layout from copybook (42 chars)
    rec = (input_record or "")[:42].ljust(42)

    def dec_slice(start: int, end: int, scale: int) -> Decimal:
        raw = rec[start:end]
        raw = raw.strip()
        if not raw:
            return Decimal('0')
        sign = 1
        if raw[0] == '+':
            raw = raw[1:]
        elif raw[0] == '-':
            sign = -1
            raw = raw[1:]
        # COBOL SIGN LEADING SEPARATE may place a leading sign in the field.
        # For this layout, deductions is 8 chars and may include a sign.
        if raw and raw[0] in '+-':
            sign = -1 if raw[0] == '-' else 1
            raw = raw[1:]
        if not raw:
            return Decimal('0')
        if not raw.isdigit():
            # Be tolerant of spaces/garbage by extracting digits only.
            digits = ''.join(ch for ch in raw if ch.isdigit())
            if not digits:
                return Decimal('0')
            raw = digits
        return Decimal(sign) * (Decimal(int(raw)) / (Decimal(10) ** scale))

    gross = dec_slice(18, 27, 2)
    tax_rate = dec_slice(27, 31, 3)
    deductions = dec_slice(31, 39, 2)
    bonus_flag = rec[39:40]

    tax_amount = (gross * tax_rate).quantize(Decimal('0.01'), rounding=ROUND_HALF_UP)
    net_amount = gross - tax_amount - deductions
    if bonus_flag == 'Y':
        net_amount += Decimal('50.00')
    if net_amount < 0:
        net_amount = Decimal('0.00')

    # Output: 9-digit zero-padded cents field (fixed-width ACH output)
    cents = int((net_amount * 100).quantize(Decimal('1'), rounding=ROUND_HALF_UP))
    return f"{cents:09d}"
"}
